spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    // 4 hops total
    // Hop 0: 0.0 to 0.15
    // Hop 1: 0.15 to 0.30
    // Hop 2: 0.30 to 0.45
    // Hop 3: 0.45 to 0.60
    // Stage 4 (Result): 0.60 to 1.0

    var hopIndex = 0;
    var hopProgress = 0;
    if (progress >= 0.15 && progress < 0.30) {
      hopIndex = 1;
      hopProgress = (progress - 0.15) / 0.15;
    } else if (progress >= 0.30 && progress < 0.45) {
      hopIndex = 2;
      hopProgress = (progress - 0.30) / 0.15;
    } else if (progress >= 0.45 && progress < 0.60) {
      hopIndex = 3;
      hopProgress = (progress - 0.45) / 0.15;
    } else if (progress >= 0.60) {
      hopIndex = 4;
      hopProgress = 1;
    }

    var midX = W / 2;
    var midY = H / 2 - 25;

    // Coordinates of digits: '3', '2', '0', '0', '0'
    var digitSpacing = 20;
    var digits = ['3', '2', '0', '0', '0'];
    var startDigitX = midX - (digits.length * digitSpacing) / 2 + 5;

    // Draw digits
    ctx.font = 'bold 20px monospace';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    for (var i = 0; i < digits.length; i++) {
      var dx = startDigitX + i * digitSpacing;

      // Fade out trailing zeros in stage 4
      if (hopIndex === 4 && i >= 2) {
        ctx.fillStyle = '#374151'; // Very dark gray
      } else {
        ctx.fillStyle = '#F3F4F6';
      }
      ctx.fillText(digits[i], dx, midY);
    }

    // Draw decimal point position
    // Positions relative to digit index:
    // Index 0: to the right of digit 4 (index 4)
    // Index 1: between index 3 and 4
    // Index 2: between index 2 and 3
    // Index 3: between index 1 and 2
    // Index 4: between index 0 and 1

    function getDecimalX(index) {
      var basePos = startDigitX + (digits.length - 1) * digitSpacing + 10;
      return basePos - index * digitSpacing;
    }

    var currentDecX = getDecimalX(0);
    if (hopIndex < 4) {
      var fromX = getDecimalX(hopIndex);
      var toX = getDecimalX(hopIndex + 1);

      // Draw a parabolic hop trajectory for visual flair
      currentDecX = fromX + (toX - fromX) * hopProgress;
      var hopY = midY + 4 - Math.sin(hopProgress * Math.PI) * 12;
    } else {
      currentDecX = getDecimalX(4);
      var hopY = midY + 4;
    }

    // Draw decimal dot
    ctx.fillStyle = '#EF4444'; // Red dot
    ctx.beginPath();
    ctx.arc(currentDecX, midY + 7, 3.5, 0, Math.PI * 2);
    ctx.fill();

    // Display current scientific notation equivalence
    ctx.font = 'bold 13px monospace';
    ctx.textAlign = 'center';

    if (hopIndex === 0) {
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Exponent: 10⁰', W / 2, midY + 36);
    } else if (hopIndex === 1) {
      ctx.fillStyle = '#F59E0B';
      ctx.fillText('Exponent: 10¹', W / 2, midY + 36);
    } else if (hopIndex === 2) {
      ctx.fillStyle = '#F59E0B';
      ctx.fillText('Exponent: 10²', W / 2, midY + 36);
    } else if (hopIndex === 3) {
      ctx.fillStyle = '#F59E0B';
      ctx.fillText('Exponent: 10³', W / 2, midY + 36);
    } else {
      ctx.fillStyle = '#10B981';
      ctx.fillText('Result: 3.2 × 10⁴', W / 2, midY + 36);
    }

    // Explanations
    ctx.font = 'bold 15px -apple-system, sans-serif';
    ctx.fillStyle = '#F3F4F6';

    if (hopIndex < 4) {
      ctx.fillText('Moving Decimal Left', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Hops count: ' + hopIndex + ' times. Exponent increases.', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#10B981';
      ctx.fillText('Standard: 32,000 = 3.2 × 10⁴', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Hops: 4 left. The trailing zeros are dropped from the coefficient.', W / 2, H - 22);
    }
  }
};
